body:
I am creating an instance of an interface inside a for generate loop. I cannot call the functions:

Here is the interface

```
interface ShiftStageIf #(parameter integer DATA_WIDTH, parameter integer META_WIDTH, parameter integer STAGE);
    typedef struct packed  {
        logic signed[2*DATA_WIDTH-1:0] data;
        logic valid;
        logic last;
        logic [META_WIDTH-1:0] meta;
    } data_t;
    data_t d;

    function automatic void init(input logic signed[DATA_WIDTH-1:0] data_in, input logic valid_in, input logic last_in, input logic [META_WIDTH-1:0] meta_in);
    begin
        d.data = 0;
        d.data[$high(d.data): $size(data_in)] = data_in;
        d.valid = valid_in;
        d.last = last_in;
        d.meta = meta_in;
    end
    endfunction

    function automatic data_t doShift(input logic stall, input logic shift);
        data_t retval;
        if(stall == 1)
            return d;

        retval = d;
        if(shift == 0)
        begin
            return retval;
        end

        retval.data = d.data[$high(d.data)] ? -1 : 0;
        retval.data[$high(d.data)-1: STAGE] = d.data[$high(d.data)-STAGE-1:0];
        return retval;
    endfunction;
endinterface

```

Inside the code that is failing:

```
